#!/usr/bin/env python3
import socket,sys,time
s=socket.socket(socket.AF_UNIX); s.connect('/tmp/qemu-monitor.sock')
time.sleep(0.2); s.recv(65536)
for cmd in sys.argv[1:]:
    s.sendall((cmd+'\n').encode()); time.sleep(0.4)
o=b''
time.sleep(0.3)
try:
    s.settimeout(0.5)
    while True: o+=s.recv(65536)
except: pass
print(o.decode(errors='replace'))

